async function saveSALeistung(id,gewerk){const name=document.getElementById('sa-l-name').value.trim();if(!name){alert('Name fehlt!');return;}const o={user_id:me.id,gewerk,name,preis:parseFloat(document.getElementById('sa-l-preis').value)||0,einheit:document.getElementById('sa-l-einheit').value};const{error}=id?await sb.from('schnellangebot_leistungen').update(o).eq('id',id):await sb.from('schnellangebot_leistungen').insert(o);if(error){alert('Fehler: '+error.message);return;}cM();pgSAEinst();}
